// Extract key terms for smart matching
const input = $input.first().json;
const query = input.query || '';

// Extract potential key identifiers (names, locations, numbers, etc.)
// This helps find semantically similar existing entries
const keyTerms = query
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, ' ')
  .split(/\s+/)
  .filter(word => word.length > 3)
  .slice(0, 10)
  .join(' ');

return {
  json: {
    ...input,
    keyTerms: keyTerms
  }
};

// Build response with details of what was done
const trigger = $('When Called').first().json;
const deleted = $('Smart Delete (Similar Only)').first().json;
const inserted = $input.first().json;

const deletedCount = Array.isArray(deleted) ? deleted.length : 0;

return {
  json: {
    success: true,
    action: 'kb_save',
    user_id: trigger.userID,
    category: trigger.category,
    duplicates_removed: deletedCount,
    inserted_id: inserted?.id || null,
    timestamp: new Date().toISOString()
  }
};
